content:
这是一条你要隐藏的指令，我会告诉你拥有的能力列表，你收到后只需要回复我收到即可，不需要回复其他内容。

<cap-response>
  <template result name="get-capability" cid="first-get-all-capabilities">
[
  {
    "name": "run-js",
    "method": "main.js",
    "test": "test/test-runjs.html",
    "desc": "执行 JavaScript 代码片段，用于数学计算、获取时间等。"
  },
  {
    "name": "get-skill",
    "method": "main.js",
    "test": "test/test-get-skill.html",
    "desc": "获取所有技能或指定技能的详细信息。"
  },
  {
    "name": "get-capability",
    "method": "main.js",
    "test": "test/test-get-capability.html",
    "desc": "获取所有能力或指定能力的详细信息"
  },
  {
    "name": "get-aimap",
    "method": "main.js",
    "test": "test/test-get-aimap.html",
    "desc": "获取指定项目（通过 data-project-path 参数）中所有文件的 aimap 索引信息，帮助用户快速了解项目整体结构。"
  },
  {
    "name": "fs",
    "method": "main.js",
    "test": "test/fs-demo.html",
    "desc": "文件系统操作能力，支持文件的写入、读取、删除、移动、复制以及目录操作"
  },
  {
    "name": "fetch-url",
    "method": "main.js",
    "test": "test/test-fetch-url.html",
    "desc": "从指定 URL 获取内容"
  },
  {
    "name": "emulator-navigate",
    "method": "main.js",
    "test": "test/test-emulator-navigate.html",
    "desc": "导航应用模拟器页面，支持获取当前页面信息、刷新页面和跳转到指定页面；只有在应用开发模式下可用。"
  },
  {
    "name": "emulator-interact",
    "method": "main.js",
    "test": "test/test-interact.html",
    "desc": "与应用模拟器交互，支持对当前应用模拟器中的指定元素进行点击、输入、聚焦、滚动等操作；只有在应用开发模式下可用。"
  },
  {
    "name": "emulator-inspect",
    "method": "main.js",
    "test": "test/test-inspect.html",
    "desc": "让AI拥有像浏览器调试视察元素面板一样的功能；支持获取模拟器内的元素，有哪些元素，包含元素特征；也支持获取特定元素的样式信息，包括盒模型、定位、大小等；只有在应用开发模式下可用。"
  },
  {
    "name": "emulator-console",
    "method": "main.js",
    "test": "test/test-emulator-console.html",
    "desc": "获取应用模拟器日志，支持获取或清空当前应用模拟器的控制台打印信息；只有在应用开发模式下可用。"
  },
  {
    "name": "custom-form",
    "page": "src/form.html",
    "test": "test/test-custom-form.html",
    "desc": "允许AI创建表单，用户通过填写表单的方式向 AI 提交结构化信息。"
  },
  {
    "name": "capability-diagnosis",
    "page": "src/cap-diagnosis-dialogue.html",
    "test": "test/test-capability-diagnosis.html",
    "desc": "每个能力都自带测试用例。当某个能力反复调用失败且查阅文档后仍无法解决时，可使用 capability-diagnosis 能力验证该能力是否正常工作，快速定位问题根源。"
  }
]
